static void dense_relu(const float *W, const float *b, const float *x,
                       float *out, int in_dim, int out_dim)
{
    for (int j = 0; j < out_dim; ++j) {
        float s = b[j];
        for (int i = 0; i < in_dim; ++i)
            s += W[j * in_dim + i] * x[i];
        out[j] = s > 0.0f ? s : 0.0f;
    }
}

static void dense(const float *W, const float *b, const float *x,
                  float *out, int in_dim, int out_dim)
{
    for (int j = 0; j < out_dim; ++j) {
        float s = b[j];
        for (int i = 0; i < in_dim; ++i)
            s += W[j * in_dim + i] * x[i];
        out[j] = s;
    }
}

static void actor_infer(const float obs[13], float action[3])
{
    float h0[64], h1[64];
    dense_relu(W0, b0, obs, h0, 13, 64);
    dense_relu(W1, b1, h0,  h1, 64, 64);
    dense(W2, b2, h1, action, 64, 3);
    for (int k = 0; k < 3; ++k)
        action[k] = tanhf(action[k]);
}

